1395     function extractMessageContent(content) {{
1396       if (content === null || content === undefined) {{
1397         return "";
1398       }}
1399       if (typeof content === "string") {{
1400         return content;
1401       }}
1402       if (Array.isArray(content)) {{
1403         return content.map((part) => {{
1404           if (typeof part === "string") {{
1405             return part;
1406           }}
1407           if (part && typeof part === "object") {{
1408             if (typeof part.text === "string") {{
1409               return part.text;
1410             }}
1411             if (typeof part.content === "string") {{
1412               return part.content;
1413             }}
1414             return JSON.stringify(part, null, 2);
1415           }}
1416           return String(part);
1417         }}).join("\\n");
1418       }}
1419       if (typeof content === "object") {{
1420         return JSON.stringify(content, null, 2);
1421       }}
1422       return String(content);
1423     }}
