1425     function extractPromptSections(payload) {{
1426       const system = [];
1427       const user = [];
1428       const assistant = [];
1429       const data = payload || {{}};
1430       if (data.system) {{
1431         system.push(extractMessageContent(data.system));
1432       }}
1433       const messages = Array.isArray(data.messages) ? data.messages : [];
1434       messages.forEach((msg) => {{
1435         const role = String(msg.role || "").toLowerCase();
1436         const text = extractMessageContent(msg.content);
1437         if (!text) {{
1438           return;
1439         }}
1440         if (role === "system") {{
1441           system.push(text);
1442         }} else if (role === "user") {{
1443           user.push(text);
1444         }} else if (role === "assistant") {{
1445           assistant.push(text);
1446         }}
1447       }});
1448       return {{ system, user, assistant }};
1449     }}
