1451     function findPairedResponse(events, callIndex) {{
1452       for (let i = callIndex + 1; i < events.length; i += 1) {{
1453         const ev = events[i];
1454         if (ev.type === "llm_response") {{
1455           return ev;
1456         }}
1457         if (ev.type === "llm_call" || ev.type === "error") {{
1458           break;
1459         }}
1460       }}
1461       return null;
1462     }}
