1464     function extractAssistantResponse(ev) {{
1465       const cassetteText = (ev && (ev.paired_response_text || ev.cassette_text)) || "";
1466       if (!cassetteText || cassetteText === "(none)") {{
1467         return "";
1468       }}
1469       try {{
1470         const data = JSON.parse(cassetteText);
1471         if (data.choices && data.choices[0]) {{
1472           const message = data.choices[0].message || {{}};
1473           const content = extractMessageContent(message.content);
1474           if (content) {{
1475             return content;
1476           }}
1477           return JSON.stringify(data.choices[0], null, 2);
1478         }}
1479         if (Array.isArray(data.content)) {{
1480           const text = data.content
1481             .filter((block) => block && block.type === "text")
1482             .map((block) => block.text || "")
1483             .join("\\n")
1484             .trim();
1485           if (text) {{
1486             return text;
1487           }}
1488         }}
1489         if (typeof data.output_text === "string") {{
1490           return data.output_text;
1491         }}
1492         return JSON.stringify(data, null, 2);
1493       }} catch (error) {{
1494         return cassetteText;
1495       }}
1496     }}
