1498     function syntaxHighlight(text) {{
1499       const escaped = escapeHtml(text);
1500       return escaped
1501         .replace(/"([^"\\\\]|\\\\.)*"/g, '<span class="hl-string">$&</span>')
1502         .replace(/\\b(true|false|null)\\b/g, '<span class="hl-keyword">$1</span>')
1503         .replace(/\\b-?\\d+(?:\\.\\d+)?(?:[eE][+-]?\\d+)?\\b/g, '<span class="hl-number">$1</span>')
1504         .replace(/([{{}}[\\],:])/g, '<span class="hl-punct">$1</span>');
1505     }}
