1507     function renderPromptBlock(text, role) {{
1508       if (!text) {{
1509         return "";
1510       }}
1511       const looksJson = text.trim().startsWith("[") || text.trim().startsWith("{{");
1512       const body = looksJson ? syntaxHighlight(text) : escapeHtml(text);
1513       return '<pre class="prompt-block ' + role + '">' + body + "</pre>";
