1516     function buildPromptViewer(ev, events, idx) {{
1517       const sections = extractPromptSections(ev.payload || {{}});
1518       let responseText = extractAssistantResponse(ev);
1519       if (!responseText) {{
1520         const paired = findPairedResponse(events, idx);
1521         if (paired) {{
1522           responseText = extractAssistantResponse(paired);
1523         }}
1524       }}
1525       let html = '<div class="prompt-viewer">';
1526       html += '<div class="inspect-label">Prompt Viewer</div>';
1527       html += '<div class="prompt-section"><div class="prompt-section-head">System Prompt</div>';
1528       if (sections.system.length) {{
1529         sections.system.forEach((text) => {{
1530           html += renderPromptBlock(text, "system");
1531         }});
1532       }} else {{
1533         html += '<div class="prompt-empty">No system prompt</div>';
1534       }}
1535       html += "</div>";
1536       html += '<div class="prompt-section"><div class="prompt-section-head">User Messages</div>';
1537       if (sections.user.length) {{
1538         sections.user.forEach((text) => {{
1539           html += renderPromptBlock(text, "user");
1540         }});
1541       }} else {{
1542         html += '<div class="prompt-empty">No user messages</div>';
1543       }}
1544       html += "</div>";
1545       html += '<div class="prompt-section"><div class="prompt-section-head">Assistant Messages (request context)</div>';
1546       if (sections.assistant.length) {{
1547         sections.assistant.forEach((text) => {{
1548           html += renderPromptBlock(text, "assistant");
1549         }});
1550       }} else {{
1551         html += '<div class="prompt-empty">No prior assistant messages in request</div>';
1552       }}
1553       html += "</div>";
1554       html += '<div class="prompt-section"><div class="prompt-section-head">Assistant Response</div>';
1555       if (responseText) {{
1556         html += renderPromptBlock(responseText, "assistant");
1557       }} else {{
1558         html += '<div class="prompt-empty">No response recorded</div>';
1559       }}
1560       html += "</div></div>";
1561       return html;
1562     }}
