1961     function replayRun(runId) {{
1962       if (replayTimer) {{
1963         clearTimeout(replayTimer);
1964         replayTimer = null;
1965       }}
1966       hideReplayPanel();
1967       const timeline = document.getElementById("timeline-" + runId);
1968       const counter = document.getElementById("replay-counter-" + runId);
1969       if (!timeline) {{
1970         return;
1971       }}
1972       const eventNodes = Array.from(timeline.querySelectorAll(".event"));
1973       const total = eventNodes.length;
1974       if (!total) {{
1975         if (counter) {{
1976           counter.textContent = "";
1977         }}
1978         return;
1979       }}
1980 
1981       eventNodes.forEach((node) => {{
1982         node.classList.remove("replay-current", "replay-past", "replay-error-highlight");
1983         node.classList.remove("expanded");
1984         const body = node.querySelector(".event-body");
1985         if (body) {{
1986           body.classList.remove("open");
1987         }}
1988       }});
1989 
1990       let index = 0;
1991       function finishReplay(message) {{
1992         setCounter(message);
1993         replayTimer = null;
1994         setTimeout(hideReplayPanel, 1200);
1995       }}
1996 
1997       function setCounter(text) {{
1998         if (counter) {{
1999           counter.textContent = text;
2000         }}
2001       }}
2002 
2003       function showStep() {{
2004         eventNodes.forEach((node, i) => {{
2005           node.classList.remove("replay-current", "replay-error-highlight");
2006           if (i < index) {{
2007             node.classList.add("replay-past");
2008           }} else {{
2009             node.classList.remove("replay-past");
2010           }}
2011         }});
2012 
2013         const current = eventNodes[index];
2014         const step = index + 1;
2015         current.classList.remove("replay-past");
2016         current.classList.add("replay-current");
2017         current.scrollIntoView({{ behavior: "smooth", block: "center" }});
2018         setCounter("Replaying step " + step + " of " + total);
2019         updateReplayPanel(runId, index);
2020 
2021         if (current.classList.contains("error")) {{
2022           current.classList.remove("replay-current");
2023           current.classList.add("replay-error-highlight");
2024           finishReplay("Stopped at error — step " + step + " of " + total);
2025           return;
2026         }}
2027 
2028         index += 1;
2029         if (index >= total) {{
2030           eventNodes.forEach((node) => node.classList.remove("replay-current"));
2031           finishReplay("Replay complete — " + total + " steps");
2032           return;
2033         }}
2034         replayTimer = setTimeout(showStep, 800);
2035       }}
2036 
2037       showStep();
2038     }}
